local function __decompress(b)local c,d,e="","",{}local f=256 local g={}for h=0,f-1 do g[h]=string.char(h)end local i=1 local function k()local l=tonumber(string.sub(b,i,i),36)i=i+1 local m=tonumber(string.sub(b,i,i+l-1),36)i=i+l return m end c=string.char(k())e[1]=c while i<=#b do local n=k()if g[n]then d=g[n]else d=c..string.sub(c,1,1)end g[f]=c..string.sub(d,1,1)e[#e+1],c,f=d,d,f+1 end return table.concat(e)end local __code=__decompress('')local __func=CompileString(__code,"Compressed",false)if __func then return __func()else error('Decompression failed')end
